/** The Partwright voxel-P mark as an app-icon tile, sized to `size`×`size` px. */
export function partwrightMarkSvg(size = 24): string {
  const id = `pwmark${++markSeq}`;
  return `<svg width="${size}" height="${size}" viewBox="0 0 104 104" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
  <defs>
    <linearGradient id="${id}tile" x1="0" y1="0" x2="104" y2="104" gradientUnits="userSpaceOnUse">
      <stop offset="0" stop-color="#1c1408"/><stop offset="1" stop-color="#0a0703"/>
    </linearGradient>
    <clipPath id="${id}clip"><rect x="0" y="0" width="104" height="104" rx="24"/></clipPath>
  </defs>
  <rect x="0" y="0" width="104" height="104" rx="24" fill="url(#${id}tile)"/>
  <g clip-path="url(#${id}clip)"><g transform="translate(4 6) scale(1.5)">${VOXEL_P_INNER}
  </g></g>
  <rect x="1" y="1" width="102" height="102" rx="23" fill="none" stroke="#f59e0b" stroke-width="1.4" stroke-opacity="0.45"/>
</svg>`;
}
